onClick:
{{
  (async () => {
    // 1. PRIMEIRO: Garante que o Store sabe onde ficar
    await storeValue("abaAtiva", "Pets");

    // 2. SEGUNDO: Muda o contexto
    await storeValue('modalContexto', {
      ...appsmith.store.modalContexto,
      entidade: 'PET',
      acaoTipo: "ADICIONAR",
			acaoBotao: "SALVAR"
    });

    // 3. TERCEIRO: Limpa os dados
    await storeValue('petSelecionado', {});

    // 4. QUARTO: Feedback visual para "travar" a UI
    showAlert("Iniciando novo pet...", "info");

    // NÃO USE resetWidget aqui de jeito nenhum por enquanto.
  })()
}}
